    uint256 time = MathUpgradeable.min(block.timestamp, epochEndTime) -
        MathUpgradeable.max(lastMintTimestamp, epochStartTime);

    emit log_named_uint("time to mint over", time);

    mintable += rate * time;

    emit log_named_uint("mintable from this iteration", rate * time);
    emit log_named_uint(
        "total mintable after this iteration",
        mintable
    );
}

unchecked {
    uint shares = _amount * _period / 365;
    uint expireEpoch = epoch[_asset] + _period;
    id = ++totalBonds;
    totalShares[_asset] += shares;
    Bond memory _bond = Bond(
        id,             // id
        address(0),     // owner
        _asset,         // tigAsset token
        _amount,        // tigAsset amount
        epoch[_asset],  // mint epoch
        block.timestamp,// mint timestamp
        expireEpoch,    // expire epoch
        0,              // pending
        shares,         // linearly scaling share of rewards
        _period,        // lock period
        false           // is expired boolean
    );
    _idToBond[id] = _bond;
    _mint(_owner, _bond);
}

if (syntheticToken_toShiftAwayFrom_marketSide > 0) {
  uint256 syntheticToken_toShiftTowardsTargetSide = getAmountSyntheticTokenToMintOnTargetSide(
    marketIndex,
    syntheticToken_toShiftAwayFrom_marketSide,
    isShiftFromLong,
    userNextPrice_currentUpdateIndex[marketIndex][user]
  );

  userNextPrice_syntheticToken_toShiftAwayFrom_marketSide[marketIndex][isShiftFromLong][user] = 0;

  require(
    ISyntheticToken(syntheticTokens[marketIndex][!isShiftFromLong]).transfer(
      user,
      syntheticToken_toShiftTowardsTargetSide
    )
  );

  emit ExecuteNextPriceMarketSideShiftSettlementUser(
    user,
    marketIndex,
    isShiftFromLong,
    syntheticToken_toShiftTowardsTargetSide
  );
}

if (collateralValueToReceive >= collateralValue) {
  // Not enough collateral for debt & liquidation fee
  collateralValueToReceive = collateralValue;
  uint256 discountedCollateralValue = a.liquidationManager().applyLiquidationDiscount(
    v.collateralType,
    collateralValue
  );

  if (currentVaultDebt > discountedCollateralValue) {
    // Not enough collateral for debt alone
    insuranceAmount = currentVaultDebt.sub(discountedCollateralValue);
    require(a.stablex().balanceOf(address(this)) >= insuranceAmount);
    a.stablex().burn(address(this), insuranceAmount); // Insurance uses local reserves to pay down debt
    emit InsurancePaid(_vaultId, insuranceAmount, msg.sender);
  }

  repayAmount = currentVaultDebt.sub(insuranceAmount);
  _amount = discountedCollateralValue;
}

